companion object {
    fun create(userId: String, items: List<OrderItem>): Order {
        require(items.isNotEmpty()) { "주문 항목이 없습니다" }
        require(userId.isNotBlank()) { "사용자 ID가 비어있을 수 없습니다" }
        return Order(userId = userId, items = items, status = OrderStatus.PENDING)
    }

    fun restore(...): Order = Order(...)
}

companion object {
    fun fromDomain(order: Order): OrderJpaEntity {
        val entity = OrderJpaEntity(...)
        val itemEntities = order.items.map { item ->
            OrderItemJpaEntity.fromDomain(item).also { it.order = entity }
        }
        entity.items.addAll(itemEntities)
        return entity
    }
}

